// assets
import { DiamondIcon, ScanIcon, ZapIcon } from "lucide-react";

// constants
const steps = [
  {
    number: "1",
    icon: DiamondIcon,
    title: "User Journey Map",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    number: "2",
    icon: ZapIcon,
    title: "User Journey Map",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    number: "3",
    icon: ScanIcon,
    title: "User Journey Map",
    description: "Better a diamond with a flaw than a pebble without one."
  }
];

//  ------------------------------ | PROCESS 4 | ------------------------------  //

export default function Process4() {
  return (
    <section className="py-20 bg-primary">
      <div className="mx-auto container px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14 flex flex-col gap-3 max-w-sm mx-auto">
          <h2 className="text-primary-foreground">
            Our Process Is Aimed To Help Your Business
          </h2>
          <p className="text-primary-foreground/70">
            Only those who risk going too far can possibly find out how far one
            can go.
          </p>
        </div>

        {/* Steps grid */}
        <div className="grid grid-cols-12 gap-8">
          {steps.map((step) => {
            const Icon = step.icon;
            return (
              <div
                key={step.number}
                className="col-span-12 sm:col-span-4 flex flex-col gap-3"
              >
                {/* Icon + number row */}
                <div className="flex items-end justify-between">
                  <Icon
                    className="size-10 text-primary-foreground/80"
                    strokeWidth={1.5}
                  />
                  <span className="text-9xl font-bold text-yellow-500 leading-none">
                    {step.number}
                  </span>
                </div>
                <h5 className="text-primary-foreground font-bold">
                  {step.title}
                </h5>
                <p className="text-primary-foreground/70 text-md">
                  {step.description}
                </p>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
